#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n, m, T;
int d[100005][2];
vector <int> e[100005];
queue <pair<int, int>> q;
void bfs () {
    memset (d, 0x3f, sizeof (d));
    d[1][0] = 0;
    q.push ({1, 0});
    while (q.size()) {
        int x = q.front ().first;
        int y = q.front ().second;
        q.pop ();
        for (int v : e[x]) {
            if (d[v][y ^ 1] > d[x][y] + 1) {
                d[v][y ^ 1] = d[x][y] + 1;
                q.push ({v, y ^ 1});
            }
        }
    }
}
signed main() {
    cin >> n >> m >> T;
    for (int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        e[u].push_back (v);
        e[v].push_back (u);
    }
    bfs ();
    while (T--) {
        int s, t;
        cin >> s >> t;
        if (d[s][t % 2] <= t) {
            cout << "Yes\n";
        } else {
            cout << "No\n";
        }
    }
    return 0;
}
